namespace sv_bba3f03684054e078708ac6be1591370.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_bba3f03684054e078708ac6be1591370.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<div class="container-fluid">
    <div class="row">
        @* ───── Left sidebar (filters) ───── *@
        <aside class="col-md-3 mb-4">
            <div class="card">
                <div class="card-header fw-semibold">Filters</div>
                <div class="card-body">
                    @* Categories *@
                    <h6>Category</h6>
                    @if (_categories is not null)
                    {
                        @foreach (var cat in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                       checked="@_selectedCategories.Contains(cat)"
                                       @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                            </div>
                        }
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label form-label-sm">Min</label>
                        <input type="number" class="form-control form-control-sm" placeholder="0"
                               @bind="_minPrice" @bind:event="oninput" min="0" step="0.01" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label form-label-sm">Max</label>
                        <input type="number" class="form-control form-control-sm" placeholder="Any"
                               @bind="_maxPrice" @bind:event="oninput" min="0" step="0.01" />
                    </div>

                    <hr />

                    @* In-stock toggle *@
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFilters" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFilters" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </aside>

        @* ───── Main content area ───── *@
        <main class="col-md-9">
            @if (_error is not null)
            {
                <div class="alert alert-danger" role="alert">
                    <strong>Error:</strong> @_error
                </div>
            }
            else if (_loading)
            {
                <div class="d-flex justify-content-center align-items-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <span class="ms-3">Loading products…</span>
                </div>
            }
            else if (_result is not null && _result.Items.Count == 0)
            {
                <div class="alert alert-info" role="alert">
                    No products found matching your criteria.
                </div>
            }
            else if (_result is not null)
            {
                @* Toolbar *@
                <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                    <div class="d-flex align-items-center gap-2">
                        <label class="form-label mb-0 text-nowrap" for="sortSelect">Sort by:</label>
                        <select id="sortSelect" class="form-select form-select-sm" style="width:auto;"
                                value="@_sortBy" @onchange="OnSortChanged">
                            <option value="price_asc">Price: Low to High</option>
                            <option value="price_desc">Price: High to Low</option>
                            <option value="name_asc">Name: A–Z</option>
                            <option value="rating_desc">Rating: Highest</option>
                        </select>
                    </div>
                    <span class="text-muted">
                        Showing @((_result.Page - 1) * _result.PageSize + 1)–@(Math.Min(_result.Page * _result.PageSize, _result.TotalCount))
                        of @_result.TotalCount products
                    </span>
                </div>

                @* Product grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <div class="card h-100 product-card" @onclick="() => OnProductClicked(product)"
                                 style="cursor:pointer;" role="button" tabindex="0">
                                @* Placeholder image *@
                                <div class="card-img-top bg-light d-flex align-items-center justify-content-center"
                                     style="height:180px;" role="img" aria-label="@product.Name">
                                    <span class="text-muted">@product.Name</span>
                                </div>
                                <div class="card-body d-flex flex-column">
                                    <h6 class="card-title">@product.Name</h6>
                                    <p class="card-text fw-bold mb-1">@product.Price.ToString("C")</p>
                                    <p class="card-text mb-1" title="@($"{product.Rating:F1} out of 5")">
                                        @RenderStars(product.Rating)
                                    </p>
                                    @if (!product.InStock)
                                    {
                                        <span class="badge bg-danger mb-2">Out of Stock</span>
                                    }
                                    <button class="btn btn-sm btn-success mt-auto"
                                            disabled="@(!product.InStock)"
                                            @onclick="() => { }" @onclick:stopPropagation="true">
                                        Add to Cart
                                    </button>
                                </div>
                            </div>
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (TotalPages > 1)
                {
                    <nav aria-label="Product pagination" class="mt-4">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(_currentPage <= 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(_currentPage - 1)"
                                        disabled="@(_currentPage <= 1)">Previous</button>
                            </li>
                            @for (int i = 1; i <= TotalPages; i++)
                            {
                                var page = i;
                                <li class="page-item @(page == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(page)">@page</button>
                                </li>
                            }
                            <li class="page-item @(_currentPage >= TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(_currentPage + 1)"
                                        disabled="@(_currentPage >= TotalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </main>
    </div>
</div>

@code {
    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    // ── state ──
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    // ── lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    // ── helpers ──
    private async Task SearchProductsAsync()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                _minPrice,
                _maxPrice,
                _inStockOnly);

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleCategory(string category, bool selected)
    {
        if (selected)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        _sortBy = e.Value?.ToString() ?? "price_asc";
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        _currentPage = page;
        await SearchProductsAsync();
    }

    private async Task OnProductClicked(Product product)
    {
        if (OnProductSelected.HasDelegate)
            await OnProductSelected.InvokeAsync(product);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

