    /// <summary>Raised when a product card is clicked so the parent can navigate to a detail page.</summary>
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    // ── state ──
    private List<string>? _categories;
    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;

    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null || _result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    // ── lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProductsAsync();
            _categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    // ── helpers ──
    private async Task SearchProductsAsync()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var filter = new ProductFilter(
                _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
                _minPrice,
                _maxPrice,
                _inStockOnly);

            _result = await ProductService.SearchAsync(filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleCategory(string category, bool selected)
    {
        if (selected)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        _sortBy = e.Value?.ToString() ?? "price_asc";
        _currentPage = 1;
        await SearchProductsAsync();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        _currentPage = page;
        await SearchProductsAsync();
    }

    private async Task OnProductClicked(Product product)
    {
        if (OnProductSelected.HasDelegate)
            await OnProductSelected.InvokeAsync(product);
    }

    private static string RenderStars(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}
